import{_ as r,o as a,c as i,ai as t}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"Bifröst Terms of Service","description":"","frontmatter":{},"headers":[],"relativePath":"legal/tos.md","filePath":"legal/tos.md"}'),s={name:"legal/tos.md"};function o(n,e,l,c,h,d){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="bifrost-terms-of-service" tabindex="-1">Bifröst Terms of Service <a class="header-anchor" href="#bifrost-terms-of-service" aria-label="Permalink to “Bifröst Terms of Service”">​</a></h1><p><strong>Last Updated:</strong> March 7, 2026</p><h2 id="_1-acceptance-of-terms" tabindex="-1">1. Acceptance of Terms <a class="header-anchor" href="#_1-acceptance-of-terms" aria-label="Permalink to “1. Acceptance of Terms”">​</a></h2><p>By inviting or using <strong>Bifröst</strong> in a Discord or Fluxer server, you agree to these Terms of Service.</p><h2 id="_2-description-of-service" tabindex="-1">2. Description of Service <a class="header-anchor" href="#_2-description-of-service" aria-label="Permalink to “2. Description of Service”">​</a></h2><p>Bifröst is a Discord bot that bridges channels between Discord and Fluxer servers and relays messages between linked channels.</p><h2 id="_3-usage-requirements" tabindex="-1">3. Usage Requirements <a class="header-anchor" href="#_3-usage-requirements" aria-label="Permalink to “3. Usage Requirements”">​</a></h2><p>By using Bifröst, you agree to:</p><ul><li>Follow the <a href="https://discord.com/terms" target="_blank" rel="noreferrer">Discord Terms of Service</a></li><li>Follow the <a href="https://discord.com/guidelines" target="_blank" rel="noreferrer">Discord Community Guidelines</a></li><li>Follow the <a href="https://fluxer.app/terms" target="_blank" rel="noreferrer">Fluxer Terms of Service</a></li><li>Follow the <a href="https://fluxer.app/guidelines" target="_blank" rel="noreferrer">Fluxer Community Guidelines</a></li><li>Not use the bot for illegal, abusive, or malicious activities</li><li>Not attempt to exploit, disrupt, or misuse the bot</li></ul><h2 id="_4-server-administrator-responsibility" tabindex="-1">4. Server Administrator Responsibility <a class="header-anchor" href="#_4-server-administrator-responsibility" aria-label="Permalink to “4. Server Administrator Responsibility”">​</a></h2><p>Server administrators are responsible for configuring the bot and managing how it is used within their server.</p><p>Messages sent in bridged channels may be transmitted to other Discord or Fluxer servers through the bridge.</p><h2 id="_5-message-relay-notice" tabindex="-1">5. Message Relay Notice <a class="header-anchor" href="#_5-message-relay-notice" aria-label="Permalink to “5. Message Relay Notice”">​</a></h2><p>Bifröst functions as a bridge between Discord and Fluxer servers.</p><p>Messages sent in channels configured with Bifröst may be automatically relayed to linked channels on other Discord or Fluxer servers.</p><p>Users should assume that messages sent in bridged channels may be visible to users outside of the original server.</p><p>Server administrators are responsible for clearly indicating which channels are bridged and informing their communities accordingly.</p><h2 id="_6-service-availability" tabindex="-1">6. Service Availability <a class="header-anchor" href="#_6-service-availability" aria-label="Permalink to “6. Service Availability”">​</a></h2><p>Bifröst is provided <strong>&quot;as is&quot;</strong> without guarantees of uptime, reliability, or availability.<br> The service may be modified, suspended, or discontinued at any time without notice.</p><h2 id="_7-limitation-of-liability" tabindex="-1">7. Limitation of Liability <a class="header-anchor" href="#_7-limitation-of-liability" aria-label="Permalink to “7. Limitation of Liability”">​</a></h2><p>The developer of Bifröst is not responsible for any damages, data loss, or issues resulting from the use or misuse of the bot.</p><h2 id="_8-open-source-and-self-hosting" tabindex="-1">8. Open Source and Self-Hosting <a class="header-anchor" href="#_8-open-source-and-self-hosting" aria-label="Permalink to “8. Open Source and Self-Hosting”">​</a></h2><p>Bifröst is open-source software released under the GNU General Public License v3.0 (GPL-3.0).</p><p>Anyone may download, modify, and self-host their own instance of the software in accordance with the license.</p><p>These Terms of Service apply only to the <strong>official publicly hosted instance</strong> of Bifröst operated by the developer.</p><p>If you are using a self-hosted instance of Bifröst operated by a third party, the operator of that instance is solely responsible for its operation and any data processing.</p><h2 id="_9-termination" tabindex="-1">9. Termination <a class="header-anchor" href="#_9-termination" aria-label="Permalink to “9. Termination”">​</a></h2><p>The developer reserves the right to restrict or block access to Bifröst for any server or user that violates these Terms or abuses the service.</p><h2 id="_10-changes-to-these-terms" tabindex="-1">10. Changes to These Terms <a class="header-anchor" href="#_10-changes-to-these-terms" aria-label="Permalink to “10. Changes to These Terms”">​</a></h2><p>These Terms of Service may be updated at any time. Continued use of the bot after changes are made constitutes acceptance of the updated Terms.</p><h2 id="_11-contact" tabindex="-1">11. Contact <a class="header-anchor" href="#_11-contact" aria-label="Permalink to “11. Contact”">​</a></h2><p>For questions or support regarding these Terms, contact:</p><p><strong>Email:</strong> <a href="mailto:contact@bifrost-bot.com" target="_blank" rel="noreferrer">contact@bifrost-bot.com</a></p>',33)])])}const m=r(s,[["render",o]]);export{p as __pageData,m as default};
